  21→// ── Cluster mode: fork one worker per CPU core ──
  22→// Set CLUSTER_ENABLED=true in production to use all CPU cores.
  23→// Disabled by default so local dev / single-core hosts work without surprises.
  24→const CLUSTER_ENABLED = process.env.CLUSTER_ENABLED === 'true';
  25→const WORKER_COUNT = parseInt(process.env.WORKER_COUNT, 10) || os.cpus().length;
  26→
  27→if (CLUSTER_ENABLED && cluster.isPrimary) {
  28→    console.log(`Primary ${process.pid} starting ${WORKER_COUNT} workers...`);
  29→    for (let i = 0; i < WORKER_COUNT; i++) {
  30→        cluster.fork();
  31→    }
  32→    cluster.on('exit', (worker, code, signal) => {
  33→        console.warn(`Worker ${worker.process.pid} exited (code=${code}, signal=${signal}). Restarting...`);
  34→        cluster.fork();
  35→    });
  36→    // Primary does nothing else — workers handle all requests
  37→} else {
  38→// ── Worker (or non-clustered) process: run Express ──
