  48→async function ensureShareFonts() {
  49→    if (fontsReady) return;
  50→    try {
  51→        if (!existsSync(FONT_DIR)) mkdirSync(FONT_DIR, { recursive: true });
  52→
  53→        const downloads = [];
  54→        if (!existsSync(FONT_PATH)) {
  55→            downloads.push(
  56→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans.ttf')
  57→                    .then(r => { if (!r.ok) throw new Error(`Font fetch failed: ${r.status}`); return r.arrayBuffer(); })
  58→                    .then(buf => writeFileSync(FONT_PATH, Buffer.from(buf)))
  59→            );
  60→        }
  61→        if (!existsSync(FONT_BOLD_PATH)) {
  62→            downloads.push(
  63→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans-Bold.ttf')
  64→                    .then(r => { if (!r.ok) throw new Error(`Bold font fetch failed: ${r.status}`); return r.arrayBuffer(); })
  65→                    .then(buf => writeFileSync(FONT_BOLD_PATH, Buffer.from(buf)))
  66→            );
  67→        }
  68→        if (downloads.length) await Promise.all(downloads);
  69→
  70→        fontsReady = true;
  71→        console.log('Share fonts ready:', FONT_DIR);
  72→    } catch (err) {
  73→        console.error('Failed to setup share fonts:', err?.message || err);
  74→    }
  75→}
