1010→const buildHealthPayload = () => ({
1011→    status: 'ok',
1012→    uptimeSeconds: Math.round(process.uptime()),
1013→    startedAt: metricsState.startedAt,
1014→    now: new Date().toISOString(),
1015→});
1016→
1017→const isMetricsAuthorized = (req) => {
1018→    if (!METRICS_TOKEN) {
1019→        return true;
1020→    }
1021→
1022→    const providedToken = String(req.headers['x-metrics-token'] || '').trim();
1023→    return Boolean(providedToken && providedToken === METRICS_TOKEN);
1024→};
1025→
1026→const buildMetricsPayload = () => {
1027→    const routeStats = Array.from(metricsState.routeStats.entries())
1028→        .map(([route, stat]) => ({
1029→            route,
1030→            count: stat.count,
1031→            avgDurationMs: stat.count > 0 ? Number((stat.totalDurationMs / stat.count).toFixed(2)) : 0,
1032→            maxDurationMs: Number(stat.maxDurationMs.toFixed(2)),
1033→            bytesSent: stat.bytesSent,
1034→            statusBuckets: stat.statusBuckets,
1035→        }))
1036→        .sort((a, b) => b.count - a.count);
1037→
1038→    return {
1039→        startedAt: metricsState.startedAt,
1040→        requests: metricsState.requests,
1041→        responses: metricsState.responses,
1042→        inFlight: metricsState.inFlight,
1043→        bytesSent: metricsState.bytesSent,
1044→        statusBuckets: metricsState.statusBuckets,
1045→        routeStats: routeStats,
1046→    };
1047→};
1048→
1049→const sendHealth = (_req, res) => {
1050→    res.set('Cache-Control', 'no-store');
1051→    return res.status(200).json(buildHealthPayload());
1052→};
1053→
1054→const sendMetrics = (req, res) => {
1055→    if (!isMetricsAuthorized(req)) {
1056→        return res.status(403).json({ error: 'forbidden' });
1057→    }
1058→
1059→    res.set('Cache-Control', 'no-store');
1060→    return res.status(200).json(buildMetricsPayload());
1061→};
