  8→const getWeekKey = () => {
  9→    const now = new Date();
 10→    const day = now.getUTCDay();
 11→    const diff = day === 0 ? 6 : day - 1;
 12→    const monday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - diff));
 13→    return `recap-dismissed-${monday.toISOString().slice(0, 10)}`;
 14→};
