  1→import React, { useState, useRef, useCallback, useEffect } from 'react';
  2→import ReactionPicker from './ReactionPicker';
  3→import ReactionBurst from './ReactionBurst';
  4→import { getReactionEmoji } from '../../utils/reactionConfig';
  5→import './reactions.css';
  6→
  7→const ReactionButton = ({ userReaction, reactionCount, onReact, disabled }) => {
  8→    const [showPicker, setShowPicker] = useState(false);
  9→    const [burstState, setBurstState] = useState(null);
 10→    const hoverTimerRef = useRef(null);
 11→    const leaveTimerRef = useRef(null);
 12→    const longPressTimerRef = useRef(null);
 13→    const longPressOpenedRef = useRef(false);
 14→    const isTouchRef = useRef(false);
 15→    const containerRef = useRef(null);
 16→
 17→    const handleMouseEnter = useCallback(() => {
 18→        if (isTouchRef.current) return;
 19→        if (leaveTimerRef.current) {
 20→            clearTimeout(leaveTimerRef.current);
 21→            leaveTimerRef.current = null;
 22→        }
 23→        hoverTimerRef.current = setTimeout(() => {
 24→            setShowPicker(true);
 25→        }, 300);
 26→    }, []);
 27→
 28→    const handleMouseLeave = useCallback(() => {
 29→        if (isTouchRef.current) return;
 30→        if (hoverTimerRef.current) {
 31→            clearTimeout(hoverTimerRef.current);
 32→            hoverTimerRef.current = null;
 33→        }
 34→        leaveTimerRef.current = setTimeout(() => {
 35→            setShowPicker(false);
 36→        }, 150);
 37→    }, []);
 38→
 39→    const handleTouchStart = useCallback(() => {
 40→        isTouchRef.current = true;
 41→        longPressTimerRef.current = setTimeout(() => {
 42→            longPressOpenedRef.current = true;
 43→            setShowPicker(true);
 44→        }, 500);
 45→    }, []);
 46→
 47→    const handleTouchEnd = useCallback(() => {
 48→        if (longPressTimerRef.current) {
 49→            clearTimeout(longPressTimerRef.current);
 50→            longPressTimerRef.current = null;
 51→        }
 52→    }, []);
 53→
 54→    // Tap-outside-to-close for mobile
 55→    useEffect(() => {
 56→        if (!showPicker || !isTouchRef.current) return;
 57→
 58→        const handleOutsideTouch = (e) => {
 59→            if (containerRef.current && !containerRef.current.contains(e.target)) {
 60→                setShowPicker(false);
 61→                isTouchRef.current = false;
 62→            }
 63→        };
 64→
 65→        document.addEventListener('touchstart', handleOutsideTouch);
 66→        return () => document.removeEventListener('touchstart', handleOutsideTouch);
 67→    }, [showPicker]);
 68→
 69→    useEffect(() => {
 70→        return () => {
 71→            if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
 72→            if (leaveTimerRef.current) clearTimeout(leaveTimerRef.current);
 73→            if (longPressTimerRef.current) clearTimeout(longPressTimerRef.current);
 74→        };
 75→    }, []);
 76→
 77→    const handleQuickClick = useCallback((e) => {
 78→        e.preventDefault();
 79→        e.stopPropagation();
 80→        if (disabled) return;
 81→
 82→        if (longPressOpenedRef.current) {
 83→            longPressOpenedRef.current = false;
 84→            return;
 85→        }
 86→
 87→        if (showPicker) {
 88→            setShowPicker(false);
 89→            isTouchRef.current = false;
 90→            return;
 91→        }
 92→
 93→        // Quick tap: toggle heart (or remove current reaction)
 94→        if (userReaction) {
 95→            onReact(userReaction); // toggle off
 96→        } else {
 97→            if (!burstState && containerRef.current) {
 98→                const rect = containerRef.current.getBoundingClientRect();
 99→                setBurstState({ emoji: getReactionEmoji('heart'), rect });
100→            }
101→            onReact('heart'); // default to heart
102→        }
103→    }, [userReaction, onReact, disabled, showPicker, burstState]);
104→
105→    const handlePickerSelect = useCallback((reactionType) => {
106→        setShowPicker(false);
107→        isTouchRef.current = false;
108→        if (!burstState && containerRef.current) {
109→            const rect = containerRef.current.getBoundingClientRect();
110→            setBurstState({ emoji: getReactionEmoji(reactionType), rect });
111→        }
112→        onReact(reactionType);
113→    }, [onReact, burstState]);
114→
115→    const hasReaction = !!userReaction;
116→    const displayEmoji = hasReaction ? getReactionEmoji(userReaction) : null;
117→
118→    return (
119→        <div
120→            className="reaction-button-container"
121→            ref={containerRef}
122→            onMouseEnter={handleMouseEnter}
123→            onMouseLeave={handleMouseLeave}
124→            onTouchStart={handleTouchStart}
125→            onTouchEnd={handleTouchEnd}
126→        >
127→            <div
128→                className={`reaction-button ${hasReaction ? 'has-reaction' : ''}`}
129→                onClick={handleQuickClick}
130→            >
131→                {hasReaction ? (
132→                    <span className="reaction-button-emoji">{displayEmoji}</span>
133→                ) : (
134→                    <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="var(--icon-default)">
135→                        <g id="style=fill">
136→                        <g id="like">
137→                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M15.9977 5.63891C16.2695 4.34931 15.433 3.00969 14.2102 2.59462C13.6171 2.37633 12.9892 2.4252 12.4662 2.60499C11.9449 2.78419 11.4461 3.12142 11.1369 3.58441L11.136 3.58573L7.49506 9.00272C8.05104 9.29585 8.43005 9.87954 8.43005 10.5518V21.3018H6.91003V21.3018H16.6801C18.2938 21.3018 19.2028 20.2977 19.8943 19.202C20.6524 18.0009 21.1453 16.7211 21.5116 15.5812C21.6808 15.0546 21.8252 14.5503 21.9547 14.0984L21.9863 13.9881C22.126 13.5007 22.2457 13.0904 22.366 12.7549C22.698 11.8292 22.5933 10.9072 22.067 10.2072C21.5476 9.5166 20.7005 9.15175 19.76 9.15175H15.76C15.6702 9.15175 15.6017 9.11544 15.5599 9.06803C15.5238 9.02716 15.4831 8.95058 15.502 8.81171L15.9977 5.63891Z"/>
138→                        <path id="rec" d="M2.18005 10.6199C2.18005 10.03 2.62777 9.55176 3.18005 9.55176H6.68005C7.23234 9.55176 7.68005 10.03 7.68005 10.6199V21.3018H3.18005C2.62777 21.3018 2.18005 20.8235 2.18005 20.2336V10.6199Z"/>
139→                        </g>
140→                        </g>
141→                    </svg>
142→                )}
143→            </div>
144→            {typeof reactionCount === 'number' && reactionCount > 0 && (
145→                <span className="reaction-count">{reactionCount}</span>
146→            )}
147→            <ReactionPicker
148→                isOpen={showPicker}
149→                onSelect={handlePickerSelect}
150→                currentReaction={userReaction}
151→            />
152→            {burstState && (
153→                <ReactionBurst
154→                    emoji={burstState.emoji}
155→                    originRect={burstState.rect}
156→                    onComplete={() => setBurstState(null)}
157→                />
158→            )}
159→        </div>
160→    );
161→};
162→
163→export default ReactionButton;
