16→export const getPromptResponsesController = async (req, res) => {
17→    try {
18→        const { promptId } = req.params;
19→        if (!promptId) {
20→            return res.status(400).json({ error: 'promptId is required' });
21→        }
22→        const { limit, before } = req.query;
23→        const result = await getPromptResponsesService(
24→            parseInt(promptId, 10),
25→            limit,
26→            before || null
27→        );
28→        return res.status(200).json(result);
29→    } catch (err) {
30→        console.error('error in getPromptResponsesController:', err);
31→        return res.status(500).json({ error: 'failed to get prompt responses' });
32→    }
